sp_rectangle_menu_item.record_script:
	// Menu Item Label
	var label = 'Awaiting Assignment Overdue';
    var daysBeforeTaskAcceptanceIsOverdue = gs.getProperty("x_153465_discovert.#DaysSinceTaskWasUnassignedOrRejectedWarning");
	var max = 5;
	var filter ='u_last_unassigned_dateISNOTEMPTY^state=-5^ORstate=11';
    var isGTA = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");

	var t = data;

	t.items = [];
	var u = gs.getUser().getID();

	t.record_watchers = [];
	t.record_watchers.push({
							'table':'x_153465_discovert_route_task_instance',
							'filter':filter
							});

   //KTORRES: BASED ON PRIMARY ASSIGNEE TA
   //------------------------------------------------------------------------------------------------------------------
   var primary_assigneeFilter = "primary_assigneeIN";
   var grPrimaryAssigneeTA = new GlideRecord('x_153465_discovert_discover_office_members');
   grPrimaryAssigneeTA.addQuery('office_task_authority', 'true');
   grPrimaryAssigneeTA.addEncodedQuery('office_memberDYNAMIC90d1921e5f510100a9ad2572f2b477fe');
   grPrimaryAssigneeTA.orderByDesc('sys_updated_on');
   grPrimaryAssigneeTA.query();

   while (grPrimaryAssigneeTA.next()) {
          primary_assigneeFilter += (',' + grPrimaryAssigneeTA.discover_office_hierarchy.toString());
        }
    //------------------------------------------------------------------------------------------------------------------
   //if(isGTA){
   //   primary_assigneeFilter += "^ORprimary_assignee.tasking_authoritiesISEMPTY";
   //}


	var a = new GlideAggregate('x_153465_discovert_route_task_instance');
	a.addEncodedQuery(filter);
	if(!isGTA){
    	a.addEncodedQuery(primary_assigneeFilter);
    }
	a.addAggregate("COUNT");
    a.addEncodedQuery('u_last_unassigned_dateRELATIVELE@dayofweek@ago@'+daysBeforeTaskAcceptanceIsOverdue); 
	a.query();

	var totcount = 0;

	if(a.next()){
		totcount = a.getAggregate("COUNT");
	}

	var z = new GlideRecord('x_153465_discovert_route_task_instance');
	z.addActiveQuery();
	if(!isGTA){
    	z.addEncodedQuery(primary_assigneeFilter);
    }
	z.addEncodedQuery(filter);
    z.addEncodedQuery('u_last_unassigned_dateRELATIVELE@dayofweek@ago@'+daysBeforeTaskAcceptanceIsOverdue); 
	z.orderByDesc('sys_updated_on');//STRY0050767 //z.orderByDesc('u_last_unassigned_date'); 
	z.setLimit(max);
	z.query();


	while (z.next()) {    
	   t.items.push({
					title: z.getValue('task_name') ,
					type: 'link',
					href: '?sys_id='+ z.getValue('sys_id') + '&view=sp&id=discovertasker_taskdetails&table=x_153465_discovert_route_task_instance'
	  }); 

	  if (!z.canRead())
		continue;

	     var a = {};
	        if (z.short_description.nil())
		       a.short_description = "(No description)";
	        a.__table = z.getTableName();
	        a.type = 'record';  
	}

	t.items.sort(function(a, b) {
	  return b.sortOrder - a.sortOrder;
	});

	t.items = t.items.slice(0, max); 
	t.count = totcount;

	var link = {};
	if(!isGTA){
      link = {
        title: gs.getMessage('View all requests'), 
        type: 'link', 
        href: '?id=discovertasker_detailsdrilldown&view=Unassigned&table=x_153465_discovert_route_task_instance&filter='  + primary_assigneeFilter+'^u_last_unassigned_dateISNOTEMPTY^state=-5^ORstate=11^u_last_unassigned_dateRELATIVELE@dayofweek@ago@' + daysBeforeTaskAcceptanceIsOverdue +'&label=' + label, 
        items: []
      };
    } else {
      link = {
        title: gs.getMessage('View all requests'), 
        type: 'link', 
        href: '?id=discovertasker_detailsdrilldown&view=Unassigned&table=x_153465_discovert_route_task_instance&filter='  + 'u_last_unassigned_dateISNOTEMPTY^state=-5^ORstate=11^u_last_unassigned_dateRELATIVELE@dayofweek@ago@' + daysBeforeTaskAcceptanceIsOverdue +'&label=' + label, 
        items: []
      };
    }
	t.items.push(link);
